class Solution:
    def smallestNumber(self, pattern: str) -> str:
        def backtrack(index, path):
            if len(path) == len(pattern) + 1:
                result.append(''.join(map(str, path)))
                return
            for i in range(1, 10):
                if i not in path:
                    if not path or (pattern[index - 1] == 'I' and path[-1] < i) or (pattern[index - 1] == 'D' and path[-1] > i):
                        path.append(i)
                        backtrack(index + 1, path)
                        path.pop()
        result = []
        backtrack(0, [])
        return min(result)
